#include <stdio.h>
#include <stdlib.h>
#include <openssl/ec.h>
#include <openssl/err.h>

int main() {
 EC_KEY *key;
 EC_GROUP *group;
 BIGNUM *private_key;
 EC_POINT *public_key;

 // Initialize the OpenSSL library
 ERR_load_crypto_strings();

 // Create a new EC key
 key = EC_KEY_new_by_curve_name(NID_secp256k1);

 // Generate a private key
 private_key = BN_new();
 EC_KEY_generate_key(key);
 BN_bin2bn(EC_KEY_get0_private_key(key), 32, private_key);

 // Compute the corresponding public key
 group = EC_KEY_get0_group(key);
 public_key = EC_POINT_new(group);
 EC_POINT_mul(group, public_key, private_key, NULL, NULL, NULL);

 // Print the private key and public key
 printf("Private key: %s\n", BN_bn2hex(private_key));
 printf("Public key: %s\n", EC_POINT_point2hex(group, public_key, POINT_CONVERSION_UNCOMPRESSED));

 // Free the memory
 EC_KEY_free(key);
 BN_free(private_key);
 EC_POINT_free(public_key);

 return 0;
}
